static std::string cond_extract_symbol(const char* text) {
    // Extract symbol from "DEFINED(SYMBOL)" pattern
    const char* p = text;
    while (*p && *p != '(') p++;
    if (*p == '(') p++;
    std::string sym;
    while (*p && *p != ')' && *p != ' ' && *p != '\t') {
        sym += toupper(*p);
        p++;
    }
    return sym;
}

static std::string cond_toupper(const std::string& s) {
    std::string r = s;
    for (auto& c : r) c = toupper(c);
    return r;
}

